"use client";

/**
 * Accordion — Generado por Concorde
 * Fuente: Figma VOYAGER · "DetailAccordions" (2007:16995)
 *
 * Card blanca (radio 4, sombra) con título (corchetes naranjas vía CardTitle,
 * editable) y un chevron en círculo naranja a la derecha. El chevron gira:
 *   · cerrado → apunta hacia abajo
 *   · abierto → apunta hacia arriba (rotate 180)
 * El contenido se expande/colapsa. Controlado o no controlado.
 * Paths/gradiente del chevron copiados tal cual del SVG.
 */

import { useId, useState } from "react";
import type { JSX, ReactNode } from "react";
import CardTitle from "./CardTitle";

export interface AccordionProps {
  /** Título (editable) — default "INFORMACIÓN GENERAL" */
  title?: string;
  /** Contenido que se expande/colapsa */
  children?: ReactNode;
  /** Abierto (controlado) */
  open?: boolean;
  /** Abierto inicial (no controlado) — default false */
  defaultOpen?: boolean;
  onOpenChange?: (open: boolean) => void;
  /** Tamaño del título en px (default 14) */
  titleSize?: number;
  className?: string;
}

const STYLE_ID = "concorde-accordion-styles";

const ACCORDION_STYLES = `
.pacc { width: 100%; font-family: var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif); }
.pacc__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  width: 100%;
  min-height: 66px;
  box-sizing: border-box;
  padding: 0 16px;
  background: #ffffff;
  border: none;
  border-radius: 4px;
  box-shadow: rgba(0,0,0,0.1) 0px 0px 16px 4px;
  cursor: pointer;
  text-align: left;
}
.pacc__chevron {
  flex-shrink: 0;
  transition: transform 0.25s cubic-bezier(0.3, 0, 0, 1);
}
.pacc--open .pacc__chevron { transform: rotate(180deg); }
.pacc__content {
  display: grid;
  grid-template-rows: 0fr;
  transition: grid-template-rows 0.25s ease;
}
.pacc--open .pacc__content { grid-template-rows: 1fr; }
.pacc__content-inner { overflow: hidden; }
.pacc__content-pad {
  padding: 12px 18px 18px;
  font-size: 14px;
  line-height: 1.6;
  color: #475569;
}
@media (prefers-reduced-motion: reduce) {
  .pacc__chevron, .pacc__content { transition: none; }
}
`;

let _stylesInjected = false;

// ─── Chevron en círculo (gradiente naranja · copiado del SVG) ───────────────

function Chevron({ gradId }: { gradId: string }): JSX.Element {
  return (
    <svg className="pacc__chevron" width="16" height="16" viewBox="0 0 16 16" fill="none" aria-hidden="true">
      <circle cx="8" cy="8" r="7.25" stroke={`url(#${gradId})`} strokeWidth="1.5" />
      <path d="M5 6.5L8 10.5L11 6.5" stroke={`url(#${gradId})`} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
      <defs>
        <linearGradient id={gradId} x1="0.667" y1="-0.333" x2="18.94" y2="17.94" gradientUnits="userSpaceOnUse">
          <stop stopColor="#FF9C3B" />
          <stop offset="0.4" stopColor="#EF852E" />
          <stop offset="1" stopColor="#BE3D00" />
        </linearGradient>
      </defs>
    </svg>
  );
}

// ─── Component ────────────────────────────────────────────────────────────────

export default function Accordion({
  title = "INFORMACIÓN GENERAL",
  children,
  open,
  defaultOpen = false,
  onOpenChange,
  titleSize = 14,
  className = "",
}: AccordionProps): JSX.Element {
  const uid = useId().replace(/:/g, "-");
  const controlled = open !== undefined;
  const [internal, setInternal] = useState(defaultOpen);
  const isOpen = controlled ? open : internal;

  if (typeof document !== "undefined" && !_stylesInjected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = ACCORDION_STYLES;
      document.head.appendChild(el);
    }
    _stylesInjected = true;
  }

  function handleToggle(): void {
    const next = !isOpen;
    if (!controlled) setInternal(next);
    onOpenChange?.(next);
  }

  const cls = ["pacc", isOpen ? "pacc--open" : "", className].filter(Boolean).join(" ");

  return (
    <>
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: ACCORDION_STYLES }} />
      <div className={cls}>
        <button
          type="button"
          className="pacc__header"
          aria-expanded={isOpen}
          aria-controls={`${uid}-panel`}
          onClick={handleToggle}
        >
          <CardTitle title={title} subtitle="" titleSize={titleSize} />
          <Chevron gradId={`pacc-grad-${uid}`} />
        </button>
        <div className="pacc__content" id={`${uid}-panel`} role="region">
          <div className="pacc__content-inner">
            <div className="pacc__content-pad">{children}</div>
          </div>
        </div>
      </div>
    </>
  );
}

"use client";

/**
 * CardTitle — Generado por Concorde
 * Fuente: Figma VOYAGER · "Title" (nodo 2877:280)
 * Sincronizado: 2026-06-12
 *
 * Título de sección con subtítulo y brackets naranjas en esquina
 * superior-izquierda (┌) e inferior-derecha (┘). Estático.
 */

import { useId } from "react";
import type { JSX } from "react";

// ─── Types ────────────────────────────────────────────────────────────────────

export interface CardTitleProps {
  /** Título (default: "SANTANDER CONSUMER") */
  title?: string;
  /** Subtítulo (default: "10 Ofertas") */
  subtitle?: string;
  /** Tamaño del título en px (default 12 · line-height = size + 4) */
  titleSize?: number;
  /** Tamaño del subtítulo en px (default 14) */
  subtitleSize?: number;
  className?: string;
}

// ─── Self-contained CSS ───────────────────────────────────────────────────────

const STYLE_ID = "concorde-cardtitle-styles";

const CARDTITLE_STYLES = `
.cardtitle {
  position: relative;
  box-sizing: border-box;
  display: inline-flex;
  flex-direction: column;
  padding: 8px 12px;
  font-family: var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif);
}
.cardtitle__title {
  margin: 0;
  font-size: 12px;
  font-weight: 600;
  line-height: 16px;
  letter-spacing: 0;
  color: #3b1782;
  white-space: nowrap;
}
.cardtitle__subtitle {
  margin: 2px 0 0;
  font-size: 13px;
  font-weight: 400;
  line-height: 1.2;
  color: #191c1c;
}
.cardtitle__bracket {
  position: absolute;
  pointer-events: none;
}
.cardtitle__bracket--tl { top: 0; left: 0; }
.cardtitle__bracket--br { bottom: 0; right: 0; transform: rotate(180deg); }
`;

let _stylesInjected = false;

// ─── Bracket (┌) — gradiente naranja #FF9639 → #EF852E 40% → #BE3D00 ────────────

function Bracket({ uid, corner }: { uid: string; corner: "tl" | "br" }): JSX.Element {
  return (
    <svg
      className={`cardtitle__bracket cardtitle__bracket--${corner}`}
      width="10"
      height="10"
      viewBox="0 0 10 10"
      fill="none"
      aria-hidden="true"
    >
      <path
        d="M7 1.022H3.769C1.923 1.022 1 1.943 1 3.784V7.007"
        stroke={`url(#${uid}-${corner})`}
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
      <defs>
        <linearGradient id={`${uid}-${corner}`} x1="4" y1="1.022" x2="4" y2="7.007" gradientUnits="userSpaceOnUse">
          <stop stopColor="#FF9639" /><stop offset="0.4" stopColor="#EF852E" /><stop offset="1" stopColor="#BE3D00" />
        </linearGradient>
      </defs>
    </svg>
  );
}

// ─── Component ────────────────────────────────────────────────────────────────

export default function CardTitle({
  title = "SANTANDER CONSUMER",
  subtitle = "10 Ofertas",
  titleSize = 12,
  subtitleSize = 14,
  className = "",
}: CardTitleProps): JSX.Element {
  const uid = useId().replace(/:/g, "-");

  if (typeof document !== "undefined" && !_stylesInjected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = CARDTITLE_STYLES;
      document.head.appendChild(el);
    }
    _stylesInjected = true;
  }

  return (
    <>
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: CARDTITLE_STYLES }} />
      <div className={["cardtitle", className].filter(Boolean).join(" ")}>
        <Bracket uid={uid} corner="tl" />
        <h3 className="cardtitle__title" style={{ fontSize: titleSize, lineHeight: `${titleSize + 4}px` }}>{title}</h3>
        {subtitle ? <p className="cardtitle__subtitle" style={{ fontSize: subtitleSize }}>{subtitle}</p> : null}
        <Bracket uid={uid} corner="br" />
      </div>
    </>
  );
}
